def is_closed_under_addition(numbers):
    for a in numbers:
        for b in numbers:
            if (a + b) not in numbers:
                return False
    return True

# Example using natural numbers
natural_numbers = [0, 1, 2, 3, 4, 5]
print(is_closed_under_addition(natural_numbers))  # Output: True

# Example using a set where closure fails
non_closed_set = [0, 1, 2, 3]
print(is_closed_under_addition(non_closed_set))  # Output: False (e.g., 3 + 1 = 4 not in set)
